export function CreateWorkspaceModal({ isOpen, onClose, onSubmit, isCreating }: CreateWorkspaceModalProps) {
    const [isConfirmed, setIsConfirmed] = useState(false);

    const form = useForm<CreateWorkspaceInput>({
        mode: 'all',
