            description: '',
            llm_provider: 'openai',
            llm_model: 'gpt-4o',
            temperature: 0.7,
            agentic_enabled: true,
            embedding_provider: 'openai',
            embedding_model: 'text-embedding-3-small',
            embedding_dim: 1536,
            chunk_size: 800,
            chunk_overlap: 150,
            rag_engine: 'basic',
            search_limit: 5,
