    // Handle re-ranker toggle sync
    useEffect(() => {
        if (selectedRerankProvider === 'none') {
            setValue('reranker_enabled', false, { shouldValidate: true });
        } else {
            setValue('reranker_enabled', true, { shouldValidate: true });
