import React from 'react';
import { AlertCircle, FileText, Database, Layers, Check, Copy, ArrowRight } from 'lucide-react';
import { cn } from '@/lib/utils';

interface DuplicateModalProps {
    isOpen: boolean;
    onClose: () => void;
    onResolve: (strategy: 'rename' | 'use_existing' | 'overwrite') => void;
    conflict: {
        type: 'exact_duplicate' | 'name_collision' | 'content_collision';
        filename: string;
        suggested_name: string;
        existing_doc?: {
            id: string;
            filename: string;
            workspace: string;
        };
    };
    isProcessing: boolean;
}

export function DuplicateModal({ isOpen, onClose, onResolve, conflict, isProcessing }: DuplicateModalProps) {
    if (!isOpen) return null;

    const renderConflictDescription = () => {
        switch (conflict.type) {
            case 'exact_duplicate':
                return "This exact file already exists in this workspace.";
            case 'name_collision':
                return "A file with this name already exists in this workspace, but the content is different.";
            case 'content_collision':
                return `This file's content already exists in the Global Vault (Workspace: ${conflict.existing_doc?.workspace}).`;
            default:
                return "A conflict was detected.";
        }
    };

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
            <div className="bg-[#121214] border border-white/10 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
                {/* Header */}
                <div className="px-6 py-4 bg-red-500/10 border-b border-red-500/20 flex items-center gap-3">
                    <AlertCircle className="text-red-500" size={24} />
                    <div>
                        <h2 className="text-h4 font-bold text-white">Duplicate Detected</h2>
                        <p className="text-tiny text-red-500/80 font-medium">{conflict.type.replace('_', ' ')}</p>
                    </div>
                </div>

                <div className="p-6">
                    <p className="text-caption text-gray-300 mb-6">
                        {renderConflictDescription()} What would you like to do?
                    </p>

                    <div className="space-y-3">
                        {/* Option 1: Use Existing (Only for content/exact match) */}
                        {(conflict.type === 'content_collision' || conflict.type === 'exact_duplicate') && (
                            <button
                                onClick={() => onResolve('use_existing')}
                                disabled={isProcessing}
                                className="w-full p-4 rounded-xl bg-white/5 border border-white/10 hover:border-blue-500/50 hover:bg-blue-500/5 transition-all text-left flex items-start gap-4 group"
                            >
                                <div className="p-2 rounded-lg bg-blue-500/10 text-blue-400 group-hover:bg-blue-500 group-hover:text-white transition-all">
                                    <Database size={20} />
                                </div>
                                <div className="flex-1">
                                    <h3 className="text-caption font-bold text-white mb-1">Use Existing from Vault</h3>
                                    <p className="text-tiny text-gray-400">Avoid duplication by linking to the existing record and reusing its index.</p>
                                </div>
                                <ArrowRight size={16} className="text-gray-600 group-hover:text-blue-500 transition-all self-center" />
                            </button>
                        )}

                        {/* Option 2: Rename */}
                        <button
                            onClick={() => onResolve('rename')}
                            disabled={isProcessing}
                            className="w-full p-4 rounded-xl bg-white/5 border border-white/10 hover:border-yellow-500/50 hover:bg-yellow-500/5 transition-all text-left flex items-start gap-4 group"
                        >
                            <div className="p-2 rounded-lg bg-yellow-500/10 text-yellow-400 group-hover:bg-yellow-500 group-hover:text-white transition-all">
                                <Copy size={20} />
                            </div>
                            <div className="flex-1">
                                <h3 className="text-caption font-bold text-white mb-1">Upload as a Copy</h3>
                                <p className="text-tiny text-gray-400">Rename this file to <span className="text-white font-mono">{conflict.suggested_name}</span> and store it separately.</p>
                            </div>
                            <ArrowRight size={16} className="text-gray-600 group-hover:text-yellow-500 transition-all self-center" />
                        </button>

                        {/* Option 3: Cancel (Hidden here, button below) */}
                    </div>
                </div>

                {/* Footer */}
                <div className="px-6 py-4 bg-black/40 border-t border-white/5 flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        disabled={isProcessing}
                        className="px-4 py-2 rounded-lg text-caption font-medium text-gray-500 hover:text-white transition-all"
                    >
                        Cancel Upload
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import {
    Upload, FileText, Trash2, Loader2,
    Database, Search, Eye,
    Plus, Filter, Shield, ArrowRight, AlertTriangle,
    ArrowRightLeft, Layers, X, Zap, ChevronDown, Network,
    Globe, Link2, Github, Folder, Music, Info,
    HardDrive, Calendar, Clock, ChevronRight
} from 'lucide-react';
import { API_BASE_URL } from '@/lib/api-config';
import Link from 'next/link';
import { API_ROUTES } from '@/lib/api-config';
import { SourceViewer } from '@/components/source-viewer';
import { cn } from '@/lib/utils';
import { motion, AnimatePresence } from 'framer-motion';
import { useError } from '@/context/error-context';
import { getIllegalCharsFound } from '@/lib/constants';
import { useTasks } from '@/context/task-context';

const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
const ALLOWED_EXTENSIONS = ['pdf', 'txt', 'md', 'docx', 'html', 'csv', 'json'];

interface Document {
    id?: string;
    name: string;
    extension: string;
    chunks: number;
    status: string;
    shared?: boolean;
    workspace_id?: string;
    workspace_name?: string;
    shared_with?: string[];
    size?: number | string;
}

// Task type is now managed globally by TaskContext

interface BackendDocument {
    id: string;
    filename: string;
    extension: string;
    chunks: number;
    status: string;
    workspace_id: string;
    workspace_name?: string;
}

interface Workspace {
    id: string;
    name: string;
}

interface KnowledgeBaseProps {
    workspaceId?: string;
    isSidebar?: boolean;
    isGlobal?: boolean;
}

export function KnowledgeBase({ workspaceId: propWorkspaceId = "default", isSidebar = false, isGlobal = false }: KnowledgeBaseProps) {
    const workspaceId = isGlobal ? "vault" : propWorkspaceId;
    const [documents, setDocuments] = useState<Document[]>([]);
    const [isUploading, setIsUploading] = useState(false);
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const [_error, setError] = useState<string | null>(null);
    const { showError } = useError();
    const { activeTasks, recentCompletedTasks } = useTasks();
    const [activeSource, setActiveSource] = useState<{ id: number; name: string; content: string | null; download_url?: string } | null>(null);
    const [isViewing, setIsViewing] = useState(false);
    const [shareTarget, setShareTarget] = useState('');
    const [searchQuery, setSearchQuery] = useState('');
    const [deletingDoc, setDeletingDoc] = useState<Document | null>(null);
    const [managingDoc, setManagingDoc] = useState<Document | null>(null);
    const [manageMode, setManageMode] = useState<'move' | 'share'>('share');
    const [isManaging, setIsManaging] = useState(false);
    const [workspaces, setWorkspaces] = useState<Workspace[]>([]);
    const [duplicateData, setDuplicateData] = useState<{
        id: string;
        name: string;
        workspace: string;
        is_duplicate: boolean;
    } | null>(null);
    const [isLinking, setIsLinking] = useState(false);
    const [isVaultBrowserOpen, setIsVaultBrowserOpen] = useState(false);
    const [vaultDocuments, setVaultDocuments] = useState<Document[]>([]);
    const [isVaultLoading, setIsVaultLoading] = useState(false);
    const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
    const [uploadMode, setUploadMode] = useState<'file' | 'url' | 'arxiv' | 'github' | 'sitemap' | 'directory' | 'audio'>('file');
    const [importUrl, setImportUrl] = useState('');
    const [githubBranch, setGithubBranch] = useState('main');
    const [statusFilter, setStatusFilter] = useState('all');
    const [workspaceFilter, setWorkspaceFilter] = useState('all');
    const [typeFilter, setTypeFilter] = useState('all');
    const [visibilityFilter, setVisibilityFilter] = useState('all');

    // Detailed Management State
    const [detailsDoc, setDetailsDoc] = useState<any | null>(null);
    const [isDetailsLoading, setIsDetailsLoading] = useState(false);
    const [isWorkspaceModalOpen, setIsWorkspaceModalOpen] = useState(false);
    const [confirmingAction, setConfirmingAction] = useState<{
        type: 'index' | 'de-index';
        workspace_id: string;
        workspace_name: string;
    } | null>(null);

    // Poll for active tasks
    const fetchDocuments = React.useCallback(async () => {
        try {
            const url = isGlobal
                ? (API_ROUTES as any).VAULT
                : `${API_ROUTES.DOCUMENTS}?workspace_id=${encodeURIComponent(workspaceId)}`;

            const res = await fetch(url);
            if (res.ok) {
                const payload = await res.json();
                const data: BackendDocument[] = payload.data || [];
                const mappedDocs = data.map((doc) => ({
                    id: doc.id,
                    name: doc.filename,
                    extension: doc.extension,
                    chunks: doc.chunks,
                    status: doc.status,
                    shared: !isGlobal && doc.workspace_id !== workspaceId,
                    workspace_id: doc.workspace_id,
                    workspace_name: doc.workspace_name || doc.workspace_id
                }));
                setDocuments(mappedDocs);
            }
        } catch (err) {
            console.error('Failed to fetch documents', err);
        }
    }, [isGlobal, workspaceId]);

    const fetchVaultDocuments = async () => {
        setIsVaultLoading(true);
        try {
            const res = await fetch((API_ROUTES as any).VAULT);
            if (res.ok) {
                const payload = await res.json();
                const data: BackendDocument[] = payload.data || [];
                const mappedDocs = data.map((doc) => ({
                    id: doc.id,
                    name: doc.filename,
                    extension: doc.extension,
                    chunks: doc.chunks,
                    status: doc.status,
                    workspace_id: doc.workspace_id,
                    workspace_name: doc.workspace_name || doc.workspace_id
                }));
                // Filter out documents already in this workspace
                const filtered = mappedDocs.filter(vd =>
                    !documents.some(d => d.name === vd.name)
                );
                setVaultDocuments(filtered);
            }
        } catch (err) {
            console.error('Failed to fetch vault', err);
        } finally {
            setIsVaultLoading(false);
        }
    };

    const handleLinkFromVault = async (doc: Document) => {
        // Fire-and-forget: submit and close modal immediately
        try {
            const res = await fetch(API_ROUTES.DOCUMENTS_UPDATE_WS, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: doc.name,
                    target_workspace_id: workspaceId,
                    action: 'link',
                    force_reindex: false
                })
            });

            if (res.ok) {
                setIsVaultBrowserOpen(false);
                // The job will appear in the global JobPanel — no need to block
            } else {
                const payload = await res.json();
                showError("Link Failed", payload.message || 'Could not link document.');
            }
        } catch (err) {
            showError("Network Error", "Transmission interrupted.");
        }
    };

    // Auto-refresh documents when tasks complete (via global TaskContext)
    const prevCompletedCountRef = React.useRef(recentCompletedTasks.length);
    useEffect(() => {
        if (recentCompletedTasks.length > prevCompletedCountRef.current) {
            fetchDocuments();
        }
        prevCompletedCountRef.current = recentCompletedTasks.length;
    }, [recentCompletedTasks.length, fetchDocuments]);

    useEffect(() => {
        if (workspaceId) {
            fetchDocuments();
        }
    }, [workspaceId, fetchDocuments]);

    useEffect(() => {
        const fetchWorkspaces = async () => {
            try {
                const res = await fetch(API_ROUTES.WORKSPACES);
                if (res.ok) {
                    const payload = await res.json();
                    setWorkspaces(payload.data || []);
                }
            } catch (err) {
                console.error('Failed to fetch workspaces', err);
            }
        };
        fetchWorkspaces();
    }, []);

    const handleUpload = async (e: React.ChangeEvent<HTMLInputElement> | { file: File }) => {
        let file: File | undefined;
        if ('target' in e) {
            file = e.target.files?.[0];
        } else {
            file = e.file;
        }

        if (!file) return;

        // Validation: File Size
        if (file.size > MAX_FILE_SIZE) {
            showError("File Too Large", `File size must be under ${MAX_FILE_SIZE / 1024 / 1024}MB.`);
            return;
        }

        // Validation: Extension
        const ext = file.name.split('.').pop()?.toLowerCase();
        if (!ext || !ALLOWED_EXTENSIONS.includes(ext)) {
            showError("Invalid File Type", `Allowed formats: ${ALLOWED_EXTENSIONS.join(', ')}`);
            return;
        }

        // Optimistic Validation
        const found = getIllegalCharsFound(file.name);
        if (found.length > 0) {
            showError("Invalid Filename", `The filename contains characters that are not allowed: ${found.join(' ')}. Please rename the file and try again.`);
            return;
        }

        setIsUploading(true);
        setError(null);

        const formData = new FormData();
        formData.append('file', file);

        try {
            const res = await fetch(`${API_ROUTES.UPLOAD}?workspace_id=${encodeURIComponent(workspaceId)}`, {
                method: 'POST',
                body: formData,
            });
            if (res.ok) {
                const payload = await res.json();
                // Success branch - payload is AppResponse
                const data = payload.data;
                if (data?.duplicate?.is_duplicate) {
                    setDuplicateData({
                        id: data.duplicate.existing_id,
                        name: data.duplicate.existing_name,
                        workspace: data.duplicate.original_workspace,
                        is_duplicate: true
                    });
                }
                setIsUploadModalOpen(false);
            } else {
                const payload = await res.json();
                let title = "Upload Failed";
                const message = payload.message || 'Upload failed';

                if (payload.code === 'VALIDATION_ERROR') {
                    title = "Validation Error";
                } else if (payload.code === 'CONFLICT_ERROR' || payload.code === 'DUPLICATE_DETECTED') {
                    title = "Duplicate Document";
                    if (payload.code === 'DUPLICATE_DETECTED' && payload.data) {
                        setDuplicateData({
                            id: payload.data.existing_doc?.id,
                            name: payload.data.existing_doc?.filename,
                            workspace: payload.data.existing_doc?.workspace,
                            is_duplicate: true
                        });
                        return; // Handle via modal
                    }
                }

                setError(message);
                showError(title, message, `File: ${file.name}`);
            }
        } catch (err) {
            setError('Connection error');
            const errorMessage = err instanceof Error ? err.message : 'Failed to reach storage.';
            showError("Network Error", errorMessage);
        } finally {
            setIsUploading(false);
        }
    };

    const handleImport = async (type: string) => {
        if (!importUrl && type !== 'directory') return;

        // Validation: URL Format
        if (type === 'url' || type === 'sitemap' || type === 'github') {
            try {
                new URL(importUrl);
            } catch (e) {
                showError("Invalid URL", "Please provide a valid HTTP/HTTPS URL.");
                return;
            }
        }

        setIsUploading(true);
        try {
            let url = '';
            let body: any = { url: importUrl };

            switch (type) {
                case 'url':
                    url = API_ROUTES.DOCUMENTS + '/import-url';
                    break;
                case 'sitemap':
                    url = API_ROUTES.DOCUMENTS + '/import-sitemap';
                    break;
                case 'github':
                    url = API_ROUTES.DOCUMENTS + '/import-github';
                    body = { url: importUrl, branch: githubBranch };
                    break;
                case 'directory':
                    url = API_ROUTES.DOCUMENTS + '/import-directory';
                    body = { path: importUrl };
                    break;
                case 'arxiv':
                    url = API_ROUTES.UPLOAD + '-arxiv';
                    break;
                default: return;
            }

            const res = await fetch(`${url}?workspace_id=${encodeURIComponent(workspaceId)}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
            });

            if (res.ok) {
                setIsUploadModalOpen(false);
                setImportUrl('');
                const payload = await res.json();
                if (payload.data?.duplicate?.is_duplicate) {
                    setDuplicateData({
                        id: payload.data.duplicate.existing_id,
                        name: payload.data.duplicate.existing_name,
                        workspace: payload.data.duplicate.original_workspace,
                        is_duplicate: true
                    });
                }
            } else {
                const payload = await res.json();
                showError("Import Failed", payload.message || 'Failed to start import', `Source: ${importUrl}`);
            }
        } catch (err) {
            showError("Network Error", "Could not connect to document service.");
        } finally {
            setIsUploading(false);
        }
    };


    const handleConfirmLink = async () => {
        if (!duplicateData) return;
        setIsLinking(true);
        try {
            const res = await fetch(API_ROUTES.DOCUMENTS_UPDATE_WS, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: duplicateData.name,
                    target_workspace_id: workspaceId,
                    action: 'link',
                    force_reindex: false
                })
            });

            if (res.ok) {
                setDuplicateData(null);
                fetchDocuments();
            } else {
                const payload = await res.json();
                showError("Link Failed", payload.message || 'Could not link existing document.');
            }
        } catch (err) {
            console.error('Link error:', err);
            showError("Network Error", "Transmission interrupted.");
        } finally {
            setIsLinking(false);
        }
    };

    const handleDelete = async (name: string, vaultDelete: boolean = false) => {
        try {
            const url = new URL(API_ROUTES.DOCUMENT_DELETE(name));
            // FIXED: Use specific document workspace context to avoid 404 in Global view
            const targetWs = deletingDoc?.workspace_id || workspaceId;
            url.searchParams.append('workspace_id', targetWs);

            if (vaultDelete) {
                url.searchParams.append('vault_delete', 'true');
            }

            const res = await fetch(url.toString(), {
                method: 'DELETE',
            });
            if (res.ok) {
                setDocuments((prev) => prev.filter((d) => d.name !== name));
                setDeletingDoc(null);
            } else {
                const payload = await res.json();
                showError("Operation Failed", payload.message || 'Document deletion failed.', `Resource: ${name}`);
            }
        } catch (err) {
            console.error('Failed to delete document', err);
            const errorMessage = err instanceof Error ? err.message : 'Failed to complete deletion request.';
            showError("Network Error", errorMessage);
        }
    };

    const handleManage = async () => {
        if (!managingDoc || !shareTarget) return;

        setIsManaging(true);
        try {
            const res = await fetch(API_ROUTES.DOCUMENTS_UPDATE_WS, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: managingDoc.name,
                    target_workspace_id: shareTarget,
                    action: manageMode,
                    force_reindex: true
                })
            });

            if (res.ok) {
                // Fire-and-forget: close modal, progress visible in JobPanel
                setManagingDoc(null);
                setShareTarget('');
            } else {
                const payload = await res.json();
                showError("Transition Failed", payload.message || 'Workspace update failed.', `Document: ${managingDoc.name}`);
            }
        } catch (err) {
            console.error('Failed to manage document', err);
            const errorMessage = err instanceof Error ? err.message : 'Transmission lost during re-indexing.';
            showError("Network Error", errorMessage);
        } finally {
            setIsManaging(false);
        }
    };

    const handleView = async (name: string) => {
        setIsViewing(true);
        try {
            const res = await fetch(API_ROUTES.DOCUMENT_GET(name));
            if (res.ok) {
                const payload = await res.json();
                const data = payload.data;
                setActiveSource({
                    id: 0,
                    name: data.name || data.filename,
                    content: data.content,
                    download_url: data.download_url
                });
                fetchDocuments(); // Refresh status/fragments after on-demand indexing

            } else {
                const payload = await res.json();
                showError("Retrieval Failure", payload.message || 'Could not fetch document content.', `Source: ${name}`);
            }
        } catch (err) {
            console.error('Failed to view document', err);
            const errorMessage = err instanceof Error ? err.message : 'Connection error.';
            showError("Network Error", errorMessage);
        } finally {
            setIsViewing(false);
        }
    };

    const handleDetailView = async (doc: Document) => {
        setIsDetailsLoading(true);
        try {
            const res = await fetch(`${API_ROUTES.DOCUMENTS}/${encodeURIComponent(doc.name)}/inspect`);
            if (res.ok) {
