'use client';

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { API_ROUTES } from '@/lib/api-config';

export interface TaskItem {
    id: string;
    type: string;
    status: string;
    progress: number;
    message: string;
    error_code: string | null;
    metadata: {
        filename?: string;
        workspace_id?: string;
        operation?: string;
        [key: string]: unknown;
    };
    workspace_id: string;
    result: Record<string, unknown> | null;
    created_at: string;
    updated_at: string;
}

interface TaskContextType {
    tasks: TaskItem[];
    activeTasks: TaskItem[];
    recentCompletedTasks: TaskItem[];
    failedTasks: TaskItem[];
    hasActiveWork: boolean;
    refreshTasks: () => Promise<void>;
    retryTask: (taskId: string) => Promise<void>;
    cancelTask: (taskId: string) => Promise<void>;
    dismissTask: (taskId: string) => void;
}

const TaskContext = createContext<TaskContextType | undefined>(undefined);

const STORAGE_KEY = 'hanachan_dismissed_tasks';

export function TaskProvider({ children }: { children: React.ReactNode }) {
    const [tasks, setTasks] = useState<TaskItem[]>([]);
    const [dismissedIds, setDismissedIds] = useState<Set<string>>(new Set());
    const [isStorageLoaded, setIsStorageLoaded] = useState(false);
    const [now, setNow] = useState(Date.now());
    const notifiedFailures = useRef<Set<string>>(new Set());

    // Load dismissed IDs from localStorage on mount
    useEffect(() => {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
            try {
                const ids = JSON.parse(saved);
                if (Array.isArray(ids)) {
                    setDismissedIds(new Set(ids));
                }
            } catch (e) {
                console.error('Failed to load dismissed tasks', e);
            }
        }
        setIsStorageLoaded(true);
    }, []);

    // Save dismissed IDs to localStorage when they change
    useEffect(() => {
        if (isStorageLoaded) {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(Array.from(dismissedIds)));
        }
    }, [dismissedIds, isStorageLoaded]);

    // Update 'now' every 10 seconds to keep filters fresh
    useEffect(() => {
        const interval = setInterval(() => setNow(Date.now()), 10000);
        return () => clearInterval(interval);
    }, []);

    const fetchTasks = useCallback(async () => {
        try {
            const res = await fetch(API_ROUTES.TASKS);
            if (res.ok) {
                const data = await res.json();
                setTasks(data.data || []);
            }
        } catch (err) {
            // Silently fail polling to avoid UI noise
        }
    }, []);

    // Poll every 2 seconds
    useEffect(() => {
        fetchTasks();
        const interval = setInterval(fetchTasks, 2000);
        return () => clearInterval(interval);
    }, [fetchTasks]);

    // Derived filtered lists
    const activeTasks = useMemo(() => tasks.filter(
        t => (t.status === 'pending' || t.status === 'processing') && !dismissedIds.has(t.id)
    ), [tasks, dismissedIds]);

    const recentCompletedTasks = useMemo(() => {
        return tasks.filter(t => {
            if (t.status !== 'completed' || dismissedIds.has(t.id)) return false;
            // Show completed tasks from the last 60 seconds
            const updatedAt = new Date(t.updated_at).getTime();
            return (now - updatedAt) < 60000;
        });
    }, [tasks, dismissedIds, now]);

    const failedTasks = useMemo(() => tasks.filter(
        t => t.status === 'failed' && !dismissedIds.has(t.id)
    ), [tasks, dismissedIds]);

    const hasActiveWork = activeTasks.length > 0;

    const retryTask = useCallback(async (taskId: string) => {
        try {
            const res = await fetch(`${API_ROUTES.TASKS}${taskId}/retry`, { method: 'POST' });
            if (res.ok) {
                // Remove from dismissed set so it reappears when retrying
                setDismissedIds(prev => {
                    const next = new Set(prev);
                    next.delete(taskId);
                    return next;
                });
                await fetchTasks();
            }
        } catch (err) {
            console.error('Retry failed', err);
        }
    }, [fetchTasks]);

    const cancelTask = useCallback(async (taskId: string) => {
        try {
            const res = await fetch(`${API_ROUTES.TASKS}${taskId}/cancel`, { method: 'POST' });
            if (res.ok) {
                // Auto-dismiss canceled tasks to keep UI clean
                setDismissedIds(prev => {
                    const next = new Set(prev);
                    next.add(taskId);
                    return next;
                });
                await fetchTasks();
            }
        } catch (err) {
            console.error('Cancel failed', err);
        }
    }, [fetchTasks]);

    const dismissTask = useCallback((taskId: string) => {
        setDismissedIds(prev => {
            const next = new Set(prev);
            next.add(taskId);
            return next;
        });
    }, []);

    return (
        <TaskContext.Provider value={{
            tasks,
            activeTasks,
            recentCompletedTasks,
            failedTasks,
            hasActiveWork,
            refreshTasks: fetchTasks,
            retryTask,
            cancelTask,
            dismissTask,
        }}>
            {children}
        </TaskContext.Provider>
    );
}

export function useTasks() {
    const context = useContext(TaskContext);
    if (!context) {
        throw new Error('useTasks must be used within a TaskProvider');
    }
    return context;
}

import { useState, useEffect, useCallback } from 'react';
import { API_ROUTES } from '@/lib/api-config';
import { useError } from '@/context/error-context';

export interface AppSettings {
    llm_provider: string;
    llm_model: string;
    embedding_provider: string;
    embedding_model: string;
    search_limit: number;
    hybrid_alpha: number;
    theme: string;
    show_reasoning: boolean;
}

export interface SettingMetadata {
    mutable: boolean;
    category: string;
    description: string;
    options?: string[];
}

export function useSettingsMetadata() {
    const [metadata, setMetadata] = useState<Record<string, SettingMetadata> | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const fetchMetadata = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await fetch(API_ROUTES.SETTINGS_METADATA);
            if (res.ok) {
                const payload = await res.json();
                if (payload.success) {
                    setMetadata(payload.data);
                    setError(null);
                } else {
                    setError(payload.message || 'Failed to parse metadata.');
                }
            } else {
                setError('Metadata service unreachable.');
            }
        } catch (err) {
            console.error('Failed to fetch settings metadata:', err);
            setError('Connection failed.');
        } finally {
            setIsLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchMetadata();
    }, [fetchMetadata]);

    return { metadata, isLoading, error, refreshSettings: fetchMetadata };
}

export function useSettings(workspaceId?: string) {
    const [settings, setSettings] = useState<AppSettings | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const { showError } = useError();

    const fetchSettings = useCallback(async () => {
        setIsLoading(true);
        try {
            const url = workspaceId
                ? `${API_ROUTES.SETTINGS}?workspace_id=${encodeURIComponent(workspaceId)}`
                : API_ROUTES.SETTINGS;
            const res = await fetch(url);
            if (!res.ok) {
                showError("Configuration Hub Offline", "Unable to retrieve synchronization parameters. Defaulting to local cache.");
                return;
            }
            const rawData = await res.json();

            // Runtime Validation - use loose schema as retrieval_mode is removed
            const { AppResponseSchema } = await import('@/lib/schemas/api');
            const payload = rawData;

            if (payload.success && payload.data) {
                setSettings(payload.data);
            }
        } catch (err) {
            console.error('Failed to fetch settings:', err);
        } finally {
            setIsLoading(false);
        }
    }, [workspaceId, showError]);

    const updateSettings = async (updates: Partial<AppSettings>) => {
        try {
            const url = workspaceId
                ? `${API_ROUTES.SETTINGS}?workspace_id=${encodeURIComponent(workspaceId)}`
                : API_ROUTES.SETTINGS;
            const res = await fetch(url, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(updates),
            });
            const data = await res.json();

            if (res.ok) {
                // The backend returns AppResponse.success_response(data=settings)
                const newSettings = data.data || data;
                setSettings(newSettings);
                return newSettings;
            } else {
                let title = "Deployment Failed";
                const message = data.message || data.detail || "The cluster rejected the configuration update.";

                if (data.code === "VALIDATION_ERROR") {
                    title = "Invalid Parameter Scope";
                }

                showError(title, message, data.params ? JSON.stringify(data.params) : undefined);
                return null;
            }
        } catch (err) {
            console.error('Failed to update settings:', err);
            showError("Transmission Failure", "Handshake timed out while deploying neural parameters.");
            return null;
        }
    };

    useEffect(() => {
        fetchSettings();
    }, [fetchSettings]);

    return { settings, updateSettings, isLoading, refreshSettings: fetchSettings };
}

import { useState, useEffect, useCallback } from 'react';
import { API_ROUTES } from '@/lib/api-config';
import { useError } from '@/context/error-context';

export interface Workspace {
    id: string;
    name: string;
    description?: string | null;
    stats?: {
        thread_count?: number;
        doc_count?: number;
    } | null;
}

export interface Thread {
    id: string;
    title?: string | null;
    updated_at?: string;
}

export interface DocumentRef {
    id: string;
    filename: string;
    chunks?: number;
}

export interface WorkspaceDetail extends Workspace {
    threads: Thread[];
    documents: DocumentRef[];
}

export function useWorkspaces() {
    const [workspaces, setWorkspaces] = useState<Workspace[]>([]);
    const [currentWorkspace, setCurrentWorkspace] = useState<Workspace | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const { showError } = useError();

    const fetchWorkspaces = useCallback(async () => {
        try {
            const res = await fetch(API_ROUTES.WORKSPACES);
            if (!res.ok) {
                // If the response is not ok, we can't assume JSON or specific structure yet, 
                // but usually our backend returns AppResponse even on error (status 400/500).
                // For now, handling network-level failures.
                showError("Connection Failed", "Unable to load your workspaces. Please check your network connection.");
                return;
            }

            const rawData = await res.json();

            // Runtime Validation
            const { AppResponseSchema } = await import('@/lib/schemas/api');
            const { WorkspaceSchema } = await import('@/lib/schemas/workspaces');
            const { z } = await import('zod');

            const ResponseSchema = AppResponseSchema(z.array(WorkspaceSchema));
            const result = ResponseSchema.safeParse(rawData);

            if (!result.success) {
                console.error("API Contract Violation:", result.error);
                showError("System Error", "The server returned an unexpected data format. Please contact support.");
                return;
            }

            const payload = result.data;
            if (!payload.success || !payload.data) {
                // Business Logic Error
                showError(payload.code || "Error", payload.message || "Failed to load workspaces.");
                return;
            }

            setWorkspaces(payload.data);

            const savedWsId = localStorage.getItem('currentWorkspaceId');
            const found = payload.data.find(ws => ws.id === savedWsId);
            if (found) {
                setCurrentWorkspace(found);
            } else if (payload.data.length > 0) {
                setCurrentWorkspace(payload.data[0]);
                localStorage.setItem('currentWorkspaceId', payload.data[0].id);
            } else {
                setCurrentWorkspace(null);
            }
        } catch (err) {
            console.error('Failed to fetch workspaces:', err);
            showError("Application Error", "An unexpected error occurred while loading workspaces.");
        } finally {
            setIsLoading(false);
        }
    }, [showError]);

    useEffect(() => {
        fetchWorkspaces();
    }, [fetchWorkspaces]);

    const selectWorkspace = (ws: Workspace) => {
        setCurrentWorkspace(ws);
        localStorage.setItem('currentWorkspaceId', ws.id);
    };

    // Zod Schema Imports (Static)
    // Note: In a real app, move these to top-level imports. 
    // Kept inside for compatibility during migration if needed, but best practice is top.

    const validateWorkspaceName = async (name: string) => {
        const { BaseCreateWorkspaceSchema } = await import('@/lib/schemas/workspaces');
        const result = BaseCreateWorkspaceSchema.shape.name.safeParse(name);
        return result.success ? null : result.error.errors[0].message;
    };

    const createWorkspace = async (payload: { name: string; description?: string; rag_engine?: string }) => {
        // Optimistic Validation with Zod
        const { CreateWorkspaceSchema } = await import('@/lib/schemas/workspaces');
        const { AppResponseSchema } = await import('@/lib/schemas/api');
        const { WorkspaceSchema } = await import('@/lib/schemas/workspaces');
        const { z } = await import('zod');

        const validationResult = CreateWorkspaceSchema.safeParse({
            name: payload.name,
            description: payload.description
        });

        if (!validationResult.success) {
            const errorMsg = validationResult.error.errors[0].message;
            showError("Invalid Input", errorMsg);
            return { success: false, error: errorMsg };
        }

        try {
            const res = await fetch(API_ROUTES.WORKSPACES, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });

            const rawData = await res.json();
            const ResponseSchema = AppResponseSchema(WorkspaceSchema);
            const result = ResponseSchema.safeParse(rawData);

            if (!result.success) {
                console.error("API Contract Violation:", result.error);
                showError("System Error", "Server response validation failed.");
                return { success: false, error: "Invalid server response" };
            }

            const appResponse = result.data;
            if (appResponse.success && appResponse.data) {
                await fetchWorkspaces();
                return { success: true, workspace: appResponse.data };
            } else {
                // Structured Business Error Handling
                let title = "Unable to Create Workspace";
                const message = appResponse.message || "System rejected creation request.";

                switch (appResponse.code) {
                    case "DUPLICATE_NAME":
                        title = "Name Unavailable";
                        break;
                    case "INVALID_NAME":
                    case "VALIDATION_ERROR":
                        title = "Input Validation Error";
                        break;
                    default:
                        if (res.status >= 500) title = "Server Failure";
                }

                showError(title, message, JSON.stringify(appResponse.data));
                return { success: false, error: message };
            }
        } catch (err) {
            console.error('Failed to create workspace:', err);
            showError("Network Error", "Handshake failed. The intelligence hub is currently unreachable.");
            return { success: false, error: 'Connection error' };
        }
    };

    const updateWorkspace = async (id: string, name: string, description?: string) => {
        const { BaseCreateWorkspaceSchema } = await import('@/lib/schemas/workspaces');
        const nameValidation = BaseCreateWorkspaceSchema.shape.name.safeParse(name);

        if (!nameValidation.success) {
            showError("Invalid Input", nameValidation.error.errors[0].message);
            return;
        }

        try {
            const res = await fetch(API_ROUTES.WORKSPACE_DETAIL(id), {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name, description })
            });

            // Parse response as generic AppResponse or Workspace
            // Assuming update returns Workspace in data on success
            const rawData = await res.json();

            // If backend standard is violated (e.g. update returns raw workspace), handle fallback or enforce
            // Based on constraints, should be AppResponse
            // Check status manually first if unsure, but let's try strict Zod
            if (res.ok) {
                await fetchWorkspaces();
            } else {
                // Handle error
                showError("Update Failed", "Could not save changes.");
            }
        } catch (err) {
            showError("Connection Error", "Could not save changes. Handshake failed during synchronization.");
            console.error('Failed to update workspace:', err);
        }
    };

    const deleteWorkspace = async (id: string, vaultDelete: boolean = false) => {
        try {
            const res = await fetch(`${API_ROUTES.WORKSPACE_DETAIL(id)}?vault_delete=${vaultDelete}`, {
                method: 'DELETE'
            });

            // Delete usually returns { status: 'success', message: ... } - minimal AppResponse
            // We can validate it too

            if (res.ok) {
                if (currentWorkspace?.id === id) {
                    localStorage.removeItem('currentWorkspaceId');
                }
                await fetchWorkspaces();
            } else {
                const data = await res.json();
                showError("Deletion Failed", data.message || 'Unable to delete workspace.');
            }
        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : 'Unknown error';
            showError("Connection Error", "Could not delete workspace. Please check your connection.");
            console.error('Failed to delete workspace:', err);
        }
    };

    const getWorkspaceDetails = async (id: string): Promise<WorkspaceDetail | null> => {
        try {
            const res = await fetch(API_ROUTES.WORKSPACE_STATS(id));
            if (res.ok) {
                const result = await res.json();
                if (result.success && result.data) {
                    return result.data;
                }
            }
            return null;
        } catch (err) {
            console.error('Failed to fetch workspace details:', err);
            return null;
        }
    };

    const shareDocument = async (sourceName: string, targetWorkspaceId: string) => {
        if (!currentWorkspace) return;
        try {
            const res = await fetch(API_ROUTES.WORKSPACE_SHARE(currentWorkspace.id), {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ source_name: sourceName, target_workspace_id: targetWorkspaceId })
            });
            return res.ok;
        } catch (err) {
            console.error('Failed to share document:', err);
            return false;
        }
    };

    return {
        workspaces,
        currentWorkspace,
        isLoading,
        error: null, // errors are shown via modal
        selectWorkspace,
        switchWorkspace: selectWorkspace, // alias for layout
        createWorkspace,
        updateWorkspace,
        deleteWorkspace,
        getWorkspaceDetails,
        shareDocument,
        refreshWorkspaces: fetchWorkspaces
    };
}

